import { buildMatchFn } from "../../_lib/buildMatchFn.mjs";
import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.mjs";

const matchOrdinalNumberPattern = /\d+/i;
const parseOrdinalNumberPattern = /\d+/i;

const matchEraPatterns = {
  narrow: /^(薪褌萤|薪褌)/i,
  abbreviated: /^(薪褌萤|薪褌)/i,
  wide: /^(薪懈泄褌懈泄薪 褌芯芯谢谢褘薪 萤屑薪萤|薪懈泄褌懈泄薪 褌芯芯谢谢褘薪)/i,
};
const parseEraPatterns = {
  any: [/^(薪褌萤|薪懈泄褌懈泄薪 褌芯芯谢谢褘薪 萤屑薪萤)/i, /^(薪褌|薪懈泄褌懈泄薪 褌芯芯谢谢褘薪)/i],
};

const matchQuarterPatterns = {
  narrow: /^(iv|iii|ii|i)/i,
  abbreviated: /^(iv|iii|ii|i) 褍谢懈褉邪谢/i,
  wide: /^[1-4]-褉 褍谢懈褉邪谢/i,
};
const parseQuarterPatterns = {
  any: [/^(i(\s|$)|1)/i, /^(ii(\s|$)|2)/i, /^(iii(\s|$)|3)/i, /^(iv(\s|$)|4)/i],
};

const matchMonthPatterns = {
  narrow: /^(xii|xi|x|ix|viii|vii|vi|v|iv|iii|ii|i)/i,
  abbreviated:
    /^(1-褉 褋邪褉|2-褉 褋邪褉|3-褉 褋邪褉|4-褉 褋邪褉|5-褉 褋邪褉|6-褉 褋邪褉|7-褉 褋邪褉|8-褉 褋邪褉|9-褉 褋邪褉|10-褉 褋邪褉|11-褉 褋邪褉|12-褉 褋邪褉)/i,
  wide: /^(薪褝谐写爷谐褝褝褉 褋邪褉|褏芯褢褉写褍谐邪邪褉 褋邪褉|谐褍褉邪胁写褍谐邪邪褉 褋邪褉|写萤褉萤胁写爷谐褝褝褉 褋邪褉|褌邪胁写褍谐邪邪褉 褋邪褉|蟹褍褉谐邪邪写褍谐邪邪褉 褋邪褉|写芯谢芯芯写褍谐邪邪褉 褋邪褉|薪邪泄屑写褍谐邪邪褉 褋邪褉|械褋写爷谐褝褝褉 褋邪褉|邪褉邪胁写褍谐邪邪褉 褋邪褉|邪褉胁邪薪 薪褝谐写爷谐褝褝褉 褋邪褉|邪褉胁邪薪 褏芯褢褉写褍谐邪邪褉 褋邪褉)/i,
};
const parseMonthPatterns = {
  narrow: [
    /^i$/i,
    /^ii$/i,
    /^iii$/i,
    /^iv$/i,
    /^v$/i,
    /^vi$/i,
    /^vii$/i,
    /^viii$/i,
    /^ix$/i,
    /^x$/i,
    /^xi$/i,
    /^xii$/i,
  ],

  any: [
    /^(1|薪褝谐写爷谐褝褝褉)/i,
    /^(2|褏芯褢褉写褍谐邪邪褉)/i,
    /^(3|谐褍褉邪胁写褍谐邪邪褉)/i,
    /^(4|写萤褉萤胁写爷谐褝褝褉)/i,
    /^(5|褌邪胁写褍谐邪邪褉)/i,
    /^(6|蟹褍褉谐邪邪写褍谐邪邪褉)/i,
    /^(7|写芯谢芯芯写褍谐邪邪褉)/i,
    /^(8|薪邪泄屑写褍谐邪邪褉)/i,
    /^(9|械褋写爷谐褝褝褉)/i,
    /^(10|邪褉邪胁写褍谐邪邪褉)/i,
    /^(11|邪褉胁邪薪 薪褝谐写爷谐褝褝褉)/i,
    /^(12|邪褉胁邪薪 褏芯褢褉写褍谐邪邪褉)/i,
  ],
};

const matchDayPatterns = {
  narrow: /^[薪写屑谢锌斜斜]/i,
  short: /^(薪褟|写邪|屑褟|谢褏|锌爷|斜邪|斜褟)/i,
  abbreviated: /^(薪褟屑|写邪胁|屑褟谐|谢褏邪|锌爷褉|斜邪邪|斜褟屑)/i,
  wide: /^(薪褟屑|写邪胁邪邪|屑褟谐屑邪褉|谢褏邪谐胁邪|锌爷褉褝胁|斜邪邪褋邪薪|斜褟屑斜邪)/i,
};
const parseDayPatterns = {
  narrow: [/^薪/i, /^写/i, /^屑/i, /^谢/i, /^锌/i, /^斜/i, /^斜/i],
  any: [/^薪褟/i, /^写邪/i, /^屑褟/i, /^谢褏/i, /^锌爷/i, /^斜邪/i, /^斜褟/i],
};

const matchDayPeriodPatterns = {
  narrow: /^(爷\.萤\.|爷\.褏\.|褕萤薪萤 写褍薪写|爷写 写褍薪写|萤谐谢萤萤|萤写萤褉|芯褉芯泄|褕萤薪萤)/i,
  any: /^(爷\.萤\.|爷\.褏\.|褕萤薪萤 写褍薪写|爷写 写褍薪写|萤谐谢萤萤|萤写萤褉|芯褉芯泄|褕萤薪萤)/i,
};
const parseDayPeriodPatterns = {
  any: {
    am: /^爷\.萤\./i,
    pm: /^爷\.褏\./i,
    midnight: /^褕萤薪萤 写褍薪写/i,
    noon: /^爷写 写褍薪写/i,
    morning: /萤谐谢萤萤/i,
    afternoon: /萤写萤褉/i,
    evening: /芯褉芯泄/i,
    night: /褕萤薪萤/i,
  },
};

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: (value) => parseInt(value, 10),
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "any",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "any",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "any",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "any",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "any",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
